#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int findContentChildren(vector<int>& g, vector<int>& s) {
        sort(g.begin(), g.end());
        sort(s.begin(), s.end());
        int child = 0, cookie = 0;
        while (child < g.size() && cookie < s.size()) {
            if (s[cookie] >= g[child]) {
                child++;
            }
            cookie++;
        }
        return child;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> g(n);
    for (int i = 0; i < n; i++) cin >> g[i];
    int m;
    if (!(cin >> m)) return 0;
    vector<int> s(m);
    for (int i = 0; i < m; i++) cin >> s[i];
    Solution sol;
    int ans = sol.findContentChildren(g, s);
    cout << ans << "\n";
    return 0;
}
